/* adc_pipeline.h — ADT 接口定义 */
typedef struct {
    uint16_t buffer[ADC_PIPE_MAX_POINTS];  /* 环形缓冲区 */
    volatile uint16_t head;                 /* DMA 写入指针 */
    volatile uint16_t tail;                 /* 滤波读取指针 */
    uint8_t  window_size;                   /* 滑动窗口大小 */
    uint8_t  bits;                          /* ADC 分辨率 12/14 */
} adc_pipeline_t;

/* 对外接口 — 信息隐藏 */
int  adc_pipeline_init(adc_pipeline_t *pipe, uint8_t window);
void adc_pipeline_feed(adc_pipeline_t *pipe, uint16_t sample);
uint32_t adc_pipeline_read(adc_pipeline_t *pipe, float *out_avg);
void adc_pipeline_flush(adc_pipeline_t *pipe);

/* adc_dma_ring.c — DMA 环形缓冲区 ADC 采集 */
#define RING_SIZE  64
static uint16_t dma_buf[RING_SIZE];          /* DMA 目标缓冲区 */
static uint16_t ring_buf[RING_SIZE];         /* 消费环形缓冲区 */
static volatile uint8_t  ring_head = 0;
static volatile uint8_t  ring_tail = 0;

/* 消费一帧数据：从 DMA 缓冲区取 N 个样本到环形缓冲区 */
static void ring_feed(void)
{
    static uint8_t idx = 0;
    ring_buf[(ring_head++) % RING_SIZE] = dma_buf[idx++];
    idx %= RING_SIZE;                          /* 防止 idx 溢出 */
}

/* DMA 传输完成回调 — 由 DMA2_Stream0_IRQHandler 间接调用 */
void HAL_ADC_ConvCpltCallback(ADC_HandleTypeDef *hadc)
{
    /* ★ 关键：必须在回调中消费 DMA 缓冲区，否则下一轮覆盖 */
    for (uint8_t i = 0; i < RING_SIZE; i++) {
        ring_feed();
    }
    /* 清除标志由 HAL 库内部完成，无需手动写 DR 寄存器 */
}

/* 滑动平均滤波：取最近 window 个样本求平均 */
float adc_slide_avg(uint8_t window)
{
    if (window > RING_SIZE) window = RING_SIZE;
    uint32_t sum = 0;
    for (uint8_t i = 0; i < window; i++) {
        sum += ring_buf[(ring_head - window + i + RING_SIZE) % RING_SIZE];
    }
    return (float)(sum / window) / 4095.0f;   /* 归一化到 0~1 */
}

