/* ========== 改进前：硬编码 + 紧耦合 ========== */
// 魔法数字 + 每个调用点重复写滤波逻辑
#define WINDOW_SIZE 8
#define FILTER_COEFF 0.75f

uint16_t read_filtered(void)
{
    uint16_t raw = HAL_ADC_GetValue(&hadc1);
    static uint16_t history[WINDOW_SIZE];
    static uint8_t idx = 0;
    history[idx++] = raw;
    if (idx >= WINDOW_SIZE) idx = 0;

    uint32_t sum = 0;
    for (uint8_t i = 0; i < WINDOW_SIZE; i++)
        sum += history[i];
    uint16_t avg = sum / WINDOW_SIZE;

    /* 指数加权移动平均 EWMA */
    static uint16_t prev = 0;
    if (prev == 0) prev = avg;
    return (uint16_t)(FILTER_COEFF * avg + (1.0f - FILTER_COEFF) * prev);
}
/* 问题：无法切换滤波模式、无法单元测试、魔法数字散落在各处 */

/* ========== 改进后：可配置 + 可测试 ========== */
typedef enum {
    FILTER_MOVING_AVERAGE = 0,
    FILTER_MOVING_MEDIAN  = 1,
    FILTER_EWMA           = 2,
} filter_mode_t;

typedef struct {
    uint16_t *buffer;
    uint8_t   capacity;
    uint8_t   write_idx;
    filter_mode_t mode;
    float     ewma_coeff;
} adc_filter_t;

uint32_t filter_process(adc_filter_t *f, uint32_t sample)
{
    f->buffer[f->write_idx++ % f->capacity] = (uint16_t)sample;

    switch (f->mode) {
    case FILTER_MOVING_AVERAGE: {
        uint32_t sum = 0;
        for (uint8_t i = 0; i < f->capacity; i++)
            sum += f->buffer[i];
        return sum / f->capacity;
    }
    case FILTER_MOVING_MEDIAN: {
        /* 简化版：复制 buffer 后冒泡排序取中间值 */
        uint16_t sorted[64];
        memcpy(sorted, f->buffer, f->capacity * 2);
        for (uint8_t i = 0; i < f->capacity - 1; i++)
            for (uint8_t j = 0; j < f->capacity - 1 - i; j++)
                if (sorted[j] > sorted[j + 1]) {
                    uint16_t tmp = sorted[j];
                    sorted[j] = sorted[j + 1];
                    sorted[j + 1] = tmp;
                }
        return sorted[f->capacity / 2];
    }
    case FILTER_EWMA:
        return (uint32_t)(f->ewma_coeff * sample +
                          (1.0f - f->ewma_coeff) *
                          (f->buffer[(f->write_idx - 1) % f->capacity]));
    }
    return sample;
}
